typedef enum {
  ACTIVE_PROFILE = 1,
  ACTIVE_INCLUDE_ROOT,
  ACTIVE_MACRO,
  ACTIVE_FORCED_INCLUDE,
  ACTIVE_CASE,
  ACTIVE_GENERATED_CASE,
  ACTIVE_INCLUDE_ONLY,
  ACTIVE_NON_ROOT,
  ACTIVE_DEFERRED_HOSTED
} active_kind_t;

typedef struct {
  active_kind_t kind;
  const char *profile;
  const char *first;
  const char *second;
  ctool_u32 value;
  ctool_bool flag;
  ctool_bool hosted_environment;
} active_row_t;

